import{_ as i,c as e,o as a,ah as r}from"./chunks/framework.Cnj7lwEt.js";const m=JSON.parse('{"title":"prompt-optimizer","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/prompt-optimizer-AI工具.md","filePath":"github汇总/AI工具/prompt-optimizer-AI工具.md"}'),o={name:"github汇总/AI工具/prompt-optimizer-AI工具.md"};function t(p,l,n,h,s,d){return a(),e("div",null,l[0]||(l[0]=[r('<h1 id="prompt-optimizer" tabindex="-1">prompt-optimizer <a class="header-anchor" href="#prompt-optimizer" aria-label="Permalink to “prompt-optimizer”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>prompt-optimizer</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>linshenkx</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>AI工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>用户在使用AI时不知道怎么写提示词，写出来的提示词效果不好，AI输出质量不理想。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>强大的AI提示词优化工具，支持一键优化提示词、多轮迭代改进、原始提示词与优化后提示词的实时对比。支持OpenAI、Gemini、DeepSeek、智谱AI、SiliconFlow等主流AI模型。支持图像生成（文生图和图生图）。高级测试模式支持上下文变量管理、多轮会话测试、工具调用（Function Calling）。支持Web应用、桌面应用、Chrome插件和Docker部署四种使用方式。支持MCP协议，可与Claude Desktop等MCP兼容应用集成。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>支持四种使用方式：Web应用、桌面应用、Chrome插件、Docker部署</li><li>一键优化提示词，支持多轮迭代改进</li><li>支持多种主流AI模型</li><li>纯客户端处理，数据不经过中间服务器，保护隐私</li><li>支持图像生成功能</li><li>支持MCP协议集成</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/linshenkx/prompt-optimizer" target="_blank" rel="noreferrer">https://github.com/linshenkx/prompt-optimizer</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要使用prompt-optimizer的用户，提供多种部署方式供选择。</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li><p><strong>检查Node.js版本</strong>（本地开发需要）</p><ul><li>执行命令：<code>node -v</code></li><li>通过标准：显示Node.js 18.0.0或更高版本</li></ul></li><li><p><strong>检查pnpm是否安装</strong>（本地开发需要）</p><ul><li>执行命令：<code>pnpm -v</code></li><li>通过标准：显示pnpm版本号</li></ul></li><li><p><strong>检查Docker是否安装</strong>（Docker部署需要）</p><ul><li>执行命令：<code>docker -v</code></li><li>通过标准：显示Docker版本号</li></ul></li></ol><h3 id="主路径-使用在线版本-推荐" tabindex="-1">主路径：使用在线版本（推荐） <a class="header-anchor" href="#主路径-使用在线版本-推荐" aria-label="Permalink to “主路径：使用在线版本（推荐）”">​</a></h3><p><strong>步骤1：访问在线版本</strong></p><ul><li>目标：直接使用在线服务</li><li>位置：浏览器</li><li>操作：访问 <a href="https://prompt.always200.com" target="_blank" rel="noreferrer">https://prompt.always200.com</a></li><li>成功标志：页面正常加载，可以看到提示词优化界面</li><li>失败处理：检查网络连接</li></ul><p><strong>步骤2：配置API密钥</strong></p><ul><li>目标：配置AI模型API密钥</li><li>位置：网页右上角设置按钮</li><li>操作：点击&quot;设置&quot;→&quot;模型管理&quot;→选择模型→输入API密钥→保存</li><li>成功标志：API密钥保存成功</li><li>失败处理：检查API密钥是否正确</li></ul><h3 id="备选路径1-docker部署" tabindex="-1">备选路径1：Docker部署 <a class="header-anchor" href="#备选路径1-docker部署" aria-label="Permalink to “备选路径1：Docker部署”">​</a></h3><p><strong>步骤1：拉取并运行容器</strong></p><ul><li>目标：使用Docker部署</li><li>位置：终端</li><li>命令：<code>docker run -d -p 8081:80 --restart unless-stopped --name prompt-optimizer linshen/prompt-optimizer</code></li><li>成功标志：容器成功启动</li><li>失败处理：检查Docker是否正确安装</li></ul><p><strong>步骤2：访问服务</strong></p><ul><li>目标：访问部署的服务</li><li>位置：浏览器</li><li>操作：访问 <a href="http://localhost:8081" target="_blank" rel="noreferrer">http://localhost:8081</a></li><li>成功标志：页面正常加载</li><li>失败处理：检查端口是否被占用</li></ul><h3 id="备选路径2-下载桌面应用" tabindex="-1">备选路径2：下载桌面应用 <a class="header-anchor" href="#备选路径2-下载桌面应用" aria-label="Permalink to “备选路径2：下载桌面应用”">​</a></h3><p><strong>步骤1：下载应用</strong></p><ul><li>目标：获取桌面应用安装包</li><li>位置：浏览器</li><li>操作：访问GitHub Releases页面下载对应平台的安装包</li><li>成功标志：安装包下载完成</li><li>失败处理：检查网络连接</li></ul><p><strong>步骤2：安装并运行</strong></p><ul><li>目标：安装并启动应用</li><li>位置：本地</li><li>操作：运行安装包，按提示完成安装，启动应用</li><li>成功标志：应用成功启动</li><li>失败处理：检查系统兼容性</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ul><li>页面或应用正常打开</li><li>可以输入提示词并点击优化按钮</li><li>优化结果正常显示</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>API连接失败</strong></p><ul><li>可能原因：跨域问题（CORS）</li><li>解决步骤：使用桌面版应用，或配置API中转服务</li></ul></li><li><p><strong>macOS提示&quot;已损坏&quot;</strong></p><ul><li>可能原因：应用未经过Apple签名</li><li>解决步骤：执行命令 <code>xattr -rd com.apple.quarantine /Applications/PromptOptimizer.app</code></li></ul></li><li><p><strong>Docker容器无法启动</strong></p><ul><li>可能原因：端口被占用</li><li>解决步骤：修改端口映射，如 <code>-p 8082:80</code></li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://github.com/linshenkx/prompt-optimizer/blob/main/docs/vercel-deployment.md" target="_blank" rel="noreferrer">Vercel部署指南</a> <a href="/网络环境.html">海外网络环境配置 →</a></li><li><a href="https://github.com/linshenkx/prompt-optimizer/blob/main/docs/development.md" target="_blank" rel="noreferrer">开发文档</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',43)]))}const b=i(o,[["render",t]]);export{m as __pageData,b as default};
